-- Rights layer v1 (country-level)
-- Sources used:
-- 1) ILGA-Europe Rainbow Map 2025 (country scores and key findings): https://www.ilga-europe.org/report/rainbow-map-2025/
-- 2) Rainbow Map 2025 PDF score sheet: https://www.ilga-europe.org/files/uploads/2025/05/2025-rainbow-map.pdf
-- 3) Rainbow Map Family category findings 2025: https://rainbowmap.ilga-europe.org/categories/family/
-- 4) ILGA World maps (global legal-framework reference): https://ilga.org/ilga-world-maps/

create table if not exists public.qa_country_rights_profiles (
  country text primary key,
  legal_level text not null default 'unknown' check (legal_level in ('good','mixed','risk','unknown')),
  rights_level text not null default 'unknown' check (rights_level in ('good','mixed','risk','unknown')),
  safety_level text not null default 'unknown' check (safety_level in ('good','mixed','risk','unknown')),
  same_sex_relations_status text not null default 'unknown' check (same_sex_relations_status in ('legal','criminalized','restricted','unknown')),
  union_status text not null default 'unknown' check (union_status in ('marriage','civil_union_or_partnership','no_protection','unknown')),
  legal_gender_recognition_status text not null default 'unknown' check (legal_gender_recognition_status in ('available','restricted','impossible','unknown')),
  anti_discrimination_status text not null default 'unknown' check (anti_discrimination_status in ('full_coverage','partial_coverage','limited_or_none','unknown')),
  what_this_means text not null default '',
  confidence text not null default 'low' check (confidence in ('high','medium','low')),
  source_legal_url text,
  source_rights_url text,
  source_safety_url text,
  source_checked_at date not null default current_date,
  needs_manual_review boolean not null default true,
  created_at timestamptz not null default now(),
  updated_at timestamptz not null default now()
);

create index if not exists qa_country_rights_profiles_levels_idx
  on public.qa_country_rights_profiles (legal_level, rights_level, safety_level);

insert into public.qa_country_rights_profiles (
  country, legal_level, rights_level, safety_level, same_sex_relations_status,
  union_status, legal_gender_recognition_status, anti_discrimination_status,
  what_this_means, confidence, source_legal_url, source_rights_url, source_safety_url, source_checked_at, needs_manual_review
) values
